# Validation helpers
def validate_account_exists(account_id):
    if account_id not in ACCOUNTS_DB:
        raise Fault(
            faultcode="Client.AccountNotFound",
            faultstring=f"Account '{account_id}' not found in the system.",
        )


def validate_account_active(account_id):
    validate_account_exists(account_id)
    if ACCOUNTS_DB[account_id]["status"] != "Active":
        raise Fault(
            faultcode="Client.AccountInactive",
            faultstring=f"Account '{account_id}' is not active. Current status: {ACCOUNTS_DB[account_id]['status']}",
        )


def validate_sufficient_funds(account_id, amount):
    if ACCOUNTS_DB[account_id]["balance"] < amount:
        raise Fault(
            faultcode="Client.InsufficientFunds",
            faultstring=f"Insufficient funds in account '{account_id}'. Available: {ACCOUNTS_DB[account_id]['balance']}, Requested: {amount}",
        )


