    def getBalance(ctx, account_id):
        """
        Retrieve the current balance for a given account.
        SOAPAction: http://financial.services.api/getBalance
        """
        logger.info(f"getBalance called for account: {account_id}")

        account_id = account_id.strip()
        validate_account_exists(account_id)

        account = ACCOUNTS_DB[account_id]

        response = BalanceResponse()
        response.account_id = account["account_id"]
        response.balance = account["balance"]
        response.currency = account["currency"]
        response.as_of_timestamp = datetime.datetime.utcnow().isoformat() + "Z"
        response.status = "Success"

        logger.info(f"Balance for {account_id}: {account['balance']} {account['currency']}")
        return response

    @rpc(
        Unicode(min_occurs=1),
        Unicode(min_occurs=1),
        Float(min_occurs=1),
        Unicode,
        _returns=TransferResult,
        _soap_action="http://financial.services.api/transferFunds",
        _in_message_name="transferFundsRequest",
        _out_message_name="transferFundsResponse",
    )
    def transferFunds(ctx, from_account_id, to_account_id, amount, description):
        """
        Transfer funds between two accounts.
        SOAPAction: http://financial.services.api/transferFunds
        """
        logger.info(
            f"transferFunds called: {from_account_id} -> {to_account_id}, amount: {amount}"
        )

        from_account_id = from_account_id.strip()
        to_account_id = to_account_id.strip()

        # Validate inputs
        if amount is None or amount <= 0:
            raise Fault(
                faultcode="Client.InvalidAmount",
                faultstring="Transfer amount must be a positive number.",
            )

        if amount > 1000000:
            raise Fault(
                faultcode="Client.AmountExceedsLimit",
                faultstring="Transfer amount exceeds the maximum single transaction limit of 1,000,000.",
            )

        if from_account_id == to_account_id:
            raise Fault(
                faultcode="Client.SameAccount",
                faultstring="Cannot transfer funds to the same account.",
            )

        # Validate both accounts exist and are active
        validate_account_active(from_account_id)
        validate_account_active(to_account_id)

        # Validate sufficient funds
        validate_sufficient_funds(from_account_id, amount)

        # Check currency match
        from_currency = ACCOUNTS_DB[from_account_id]["currency"]
        to_currency = ACCOUNTS_DB[to_account_id]["currency"]
        if from_currency != to_currency:
            raise Fault(
                faultcode="Client.CurrencyMismatch",
                faultstring=f"Currency mismatch: source account uses {from_currency}, destination uses {to_currency}. Cross-currency transfers are not supported.",
            )

        # Execute transfer
        transaction_id = f"TXN-{uuid.uuid4().hex[:12].upper()}"
        timestamp = datetime.datetime.utcnow().isoformat() + "Z"

        ACCOUNTS_DB[from_account_id]["balance"] -= amount
        ACCOUNTS_DB[to_account_id]["balance"] += amount

        # Round to avoid floating point issues
        ACCOUNTS_DB[from_account_id]["balance"] = round(
            ACCOUNTS_DB[from_account_id]["balance"], 2
        )
        ACCOUNTS_DB[to_account_id]["balance"] = round(
            ACCOUNTS_DB[to_account_id]["balance"], 2
        )

        # Log transaction
        transaction = {
            "transaction_id": transaction_id,
            "from_account": from_account_id,
            "to_account": to_account_id,
            "amount": amount,
            "currency": from_currency,
            "timestamp": timestamp,
            "status": "Completed",
            "description": description or "Fund Transfer",
        }
        TRANSACTION_LOG.append(transaction)

        # Build response
        result = TransferResult()
        result.transaction_id = transaction_id
        result.from_account = from_account_id
        result.to_account = to_account_id
        result.amount = amount
        result.currency = from_currency
        result.status = "Completed"
        result.timestamp = timestamp
        result.from_new_balance = ACCOUNTS_DB[from_account_id]["balance"]
        result.to_new_balance = ACCOUNTS_DB[to_account_id]["balance"]
        result.message = f"Successfully transferred {amount} {from_currency} from {from_account_id} to {to_account_id}."

        logger.info(f"Transfer completed: {transaction_id}")
        return result

