    def getTransactionHistory(ctx, account_id):
        """
        Retrieve transaction history for a given account.
        SOAPAction: http://financial.services.api/getTransactionHistory
        """
        logger.info(f"getTransactionHistory called for account: {account_id}")

        account_id = account_id.strip()
        validate_account_exists(account_id)

        # Filter transactions for this account
        account_transactions = [
            txn
            for txn in TRANSACTION_LOG
            if txn["from_account"] == account_id or txn["to_account"] == account_id
        ]

        response = TransactionHistoryResponse()
        response.account_id = account_id
        response.total_transactions = len(account_transactions)

